import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import Image from './phonk_wallpaper.jpg';
import reportWebVitals from './reportWebVitals';

const flag = false

function Header() {
  return(<header>
    <p id="sait_name">DSpark Store</p>
  </header>
  )
}

function Footer() {
  return(<footer>
    <p>О компании DSPARK</p>
  </footer>
  )
}

function LastNews() {
  return (
    <p>{flag === true ? "Не наводися сюда" : ""}Тут вообще должна быть самая последняя новость, но так как я очень ленивый, здесь просто написана всякая фигня : )</p>
  )
}

function MouseOver() {
  console.log("Да, бывает...")
  const flag = true
}

function Wrapper() {
  return(
  <div id="wrapper">
    <Header />
    <div id="content">
      <div id="news" onMouseOver={MouseOver}>
        <p class="name_card">Новости</p>
        <div id="news_place">
          <LastNews/>
        </div>
      </div>
      <div id="game_shop" class="game_item_shop_card">
        <p class="name_card">Магазин</p>
        <img src={Image} alt="Хаха"/>
      </div>
      <div id="item_store" class="game_item_shop_card">
        <p class="name_card">Торговая площадка</p>
        <img src={Image} alt="Хаха"></img>
      </div>
    </div>
    <Footer />
  </div>
  )
}


const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<Wrapper />);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals(console.log);
